import { useState, useEffect, useRef } from 'react';
import AnimatedPage from '../components/AnimatedPage';
import { ResearchSubNav } from './ResearchDashboardPage';
import { api } from '../utils/api';
import s from './ResearchSweepPage.module.css';

const SWEEP_STAGES = ['coarse', 'refine', 'robustness'];

export default function ResearchSweepPage() {
  const [status, setStatus] = useState(null);
  const [latest, setLatest] = useState(null);
  const [logs, setLogs] = useState([]);
  const logsRef = useRef([]);

  useEffect(() => {
    // Initial fetch
    Promise.all([api('/research/status'), api('/research/latest')]).then(([st, l]) => {
      setStatus(st);
      setLatest(l);
      if (st) {
        logsRef.current = [{
          ts: new Date().toLocaleTimeString(),
          msg: `Status: ${st.status} | Stage: ${st.stage} | ${st.cases_done}/${st.cases_total}`,
        }];
        setLogs([...logsRef.current]);
      }
    });
  }, []);

  // Auto-poll every 3s
  useEffect(() => {
    const iv = setInterval(async () => {
      const st = await api('/research/status');
      if (!st) return;
      setStatus(st);

      // Append log entry if changed
      const lastLog = logsRef.current[logsRef.current.length - 1];
      const newMsg = `Status: ${st.status} | Stage: ${st.stage} | ${st.cases_done}/${st.cases_total}`;
      if (!lastLog || lastLog.msg !== newMsg) {
        logsRef.current = [...logsRef.current.slice(-9), { ts: new Date().toLocaleTimeString(), msg: newMsg }];
        setLogs([...logsRef.current]);
      }

      // Refresh latest when complete
      if (st.status === 'complete') {
        const l = await api('/research/latest');
        setLatest(l);
      }
    }, 3000);
    return () => clearInterval(iv);
  }, []);

  const isRunning = status && status.status !== 'complete' && status.status !== 'idle';
  const stages = latest?.stages || {};

  return (
    <AnimatedPage>
      <div className={s.page}>
        <ResearchSubNav />

        <h1 className={s.pageTitle}>Sweep Monitor</h1>

        {/* Status card */}
        <div className={s.statusCard}>
          <div className={s.statusHeader}>
            <div className={s.statusLeft}>
              <span className={isRunning ? s.statusDotRunning : status?.status === 'complete' ? s.statusDotComplete : s.statusDotIdle} />
              <span className={s.statusLabel}>
                {isRunning ? 'Sweep In Progress' : status?.status === 'complete' ? 'Sweep Complete' : 'No Active Sweep'}
              </span>
            </div>
            {status?.elapsed_sec && (
              <span className={s.elapsed}>{status.elapsed_sec.toFixed(0)}s elapsed</span>
            )}
          </div>

          {/* Progress bar */}
          {status && (
            <>
              <div className={s.progressRow}>
                <span className={s.progressStage}>
                  Stage: <span className={s.progressStageValue}>{status.stage || 'none'}</span>
                </span>
                <span className={s.progressCounts}>
                  {status.cases_done}/{status.cases_total} ({status.pct}%)
                </span>
              </div>
              <div className={s.progressTrack}>
                <div
                  className={isRunning ? s.progressFillRunning : s.progressFillComplete}
                  style={{ width: `${status.pct || 0}%` }}
                />
              </div>
            </>
          )}
        </div>

        {/* Stage timeline */}
        <div className={s.timelineSection}>
          <h2 className={s.sectionTitle}>Stage Timeline</h2>
          <div className={s.timelineRow}>
            {SWEEP_STAGES.map(stage => {
              const count = stages[stage] || 0;
              const isActive = status?.stage === stage;
              const isDone = count > 0 && !isActive;
              return (
                <div
                  key={stage}
                  className={s.stageCard}
                  style={{ border: `1px solid ${isActive ? '#F59E0B60' : isDone ? '#22C55E40' : 'var(--color-border, rgba(255,255,255,0.06))'}` }}
                >
                  <div className={s.stageIcon}>
                    {isDone ? (
                      <svg width="20" height="20" viewBox="0 0 20 20" fill="none">
                        <circle cx="10" cy="10" r="9" stroke="#22C55E" strokeWidth="1.5" />
                        <path d="M6 10l3 3 5-6" stroke="#22C55E" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round" />
                      </svg>
                    ) : isActive ? (
                      <div className={s.spinner} />
                    ) : (
                      <svg width="20" height="20" viewBox="0 0 20 20" fill="none">
                        <circle cx="10" cy="10" r="9" stroke="#30363D" strokeWidth="1.5" />
                      </svg>
                    )}
                  </div>
                  <div className={isActive ? s.stageNameActive : isDone ? s.stageNameDone : s.stageNamePending}>
                    {stage}
                  </div>
                  <div className={s.stageCount}>{count} cases</div>
                </div>
              );
            })}
          </div>
        </div>

        {/* Log tail */}
        <div className={s.logSection}>
          <h2 className={s.sectionTitle}>Activity Log</h2>
          <div className={s.logContainer}>
            {logs.length === 0 ? (
              <div className={s.logEmpty}>No activity</div>
            ) : (
              logs.map((log, i) => (
                <div key={i} className={s.logEntry}>
                  <span className={s.logTs}>[{log.ts}]</span> {log.msg}
                </div>
              ))
            )}
          </div>
        </div>

        {/* Empty state with last run info */}
        {!isRunning && latest && !latest.error && (
          <div className={s.lastRunCard}>
            <div className={s.lastRunText}>
              Last run: <span className={s.lastRunValue}>{latest.run_id}</span>
              {' | '}
              <span className={s.lastRunValue}>{latest.total_cases} cases</span>
              {' | '}
              <span className={s.lastRunValue}>{latest.elapsed_sec?.toFixed(0)}s</span>
            </div>
          </div>
        )}
      </div>
    </AnimatedPage>
  );
}
